	defer cur.Close(context.Background())
	for cur.Next(context.Background()) {
		var doc bson.D
		err := cur.Decode(&doc)
		if err != nil {
			log.Println("Error decoding document:", err)
			continue
		}
		log.Printf("%+v\n", doc)
	}
	if err := cur.Err(); err != nil {
		log.Fatal(err)
	}
